//! Generates `vm-js`'s Unicode simple case folding (`scf`) table.
//!
//! Usage (from repo root):
//! ```bash
//! bash vendor/ecma-rs/scripts/cargo_agent.sh run -p vm-js --bin gen_unicode_case_folding
//! ```
//!
//! This reads Unicode 17.0.0 `CaseFolding.txt` from:
//! `tools/unicode/ucd-17.0.0/CaseFolding.txt`
//! and writes:
//! `vendor/ecma-rs/vm-js/src/unicode_case_folding.rs`

use std::collections::BTreeMap;
use std::fs;
use std::path::{Path, PathBuf};

fn main() {
  if let Err(err) = run() {
    eprintln!("error: {err}");
    std::process::exit(1);
  }
}

fn run() -> Result<(), String> {
  let repo_root = repo_root()?;
  let input = repo_root.join("tools/unicode/ucd-17.0.0/CaseFolding.txt");
  let output = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("src/unicode_case_folding.rs");

  let generated = generate_scf_module(&input)?;

  fs::write(&output, generated)
    .map_err(|e| format!("writing {output:?}: {e}"))?;
  Ok(())
}

fn repo_root() -> Result<PathBuf, String> {
  // `vendor/ecma-rs/vm-js` -> repo root is `../../..`.
  let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
  Ok(manifest_dir.join("../../.."))
}

fn generate_scf_module(path: &Path) -> Result<String, String> {
  let contents = fs::read_to_string(path)
    .map_err(|e| format!("reading CaseFolding data from {path:?}: {e}"))?;

  // Use `BTreeMap` so output is naturally sorted by source code point.
  let mut mappings: BTreeMap<u32, u32> = BTreeMap::new();

  for (idx, raw_line) in contents.lines().enumerate() {
    let line_no = idx + 1;
    let line = raw_line.split('#').next().unwrap_or("").trim();
    if line.is_empty() {
      continue;
    }

    let mut parts: Vec<&str> = line.split(';').map(|p| p.trim()).collect();
    while parts.last().is_some_and(|v| v.is_empty()) {
      parts.pop();
    }
    if parts.len() != 3 {
      return Err(format!(
        "invalid CaseFolding line {line_no}: expected 3 ';' separated fields (<code>; <status>; <mapping>;), got {}",
        parts.len()
      ));
    }
    let from_raw = parts[0];
    let status = parts[1];
    let mapping_raw = parts[2];

    // Unicode simple case folding uses status C + S (see header of CaseFolding.txt).
    //
    // - C: common case folding mapping
    // - S: simple case folding mapping
    // - F: full case folding mapping (multi-code-point; ignore)
    // - T: Turkic mapping (ignore)
    let include = match status {
      "C" | "S" => true,
      "F" | "T" => false,
      other => {
        return Err(format!(
          "invalid CaseFolding line {line_no}: unknown status {other:?}"
        ))
      }
    };
    if !include {
      continue;
    }

    let from = parse_hex_code_point(from_raw).map_err(|e| {
      format!("invalid CaseFolding line {line_no}: bad code point {from_raw:?}: {e}")
    })?;
    if (0xD800..=0xDFFF).contains(&from) {
      return Err(format!(
        "invalid CaseFolding line {line_no}: surrogate code point in mapping table: {from_raw:?}"
      ));
    }

    let mut mapping_iter = mapping_raw.split_whitespace();
    let to_raw = mapping_iter
      .next()
      .ok_or_else(|| format!("invalid CaseFolding line {line_no}: empty mapping field"))?;
    let to = parse_hex_code_point(to_raw).map_err(|e| {
      format!("invalid CaseFolding line {line_no}: bad mapping {mapping_raw:?}: {e}")
    })?;
    // For C/S mappings, CaseFolding.txt must map one code point to one code point. Treat any
    // multi-code-point mapping as an error so we do not silently truncate full case folds.
    if mapping_iter.next().is_some() {
      return Err(format!(
        "invalid CaseFolding line {line_no}: expected single code point mapping for status {status:?}, got {mapping_raw:?}"
      ));
    }
    if (0xD800..=0xDFFF).contains(&to) {
      return Err(format!(
        "invalid CaseFolding line {line_no}: surrogate code point in mapping target: {to_raw:?}"
      ));
    }

    if from == to {
      // Identity mapping: not stored.
      continue;
    }

    if let Some(prev) = mappings.insert(from, to) {
      if prev != to {
        return Err(format!(
          "invalid CaseFolding line {line_no}: duplicate mapping for {from_raw:?}: 0x{prev:04X} vs 0x{to:04X}"
        ));
      }
    }
  }

  let mut out = String::new();
  out.push_str("//! Unicode simple case folding (`scf`) table.\n");
  out.push_str("//!\n");
  out.push_str("//! This file is @generated by `cargo run -p vm-js --bin gen_unicode_case_folding`.\n");
  out.push_str("//! Source: `tools/unicode/ucd-17.0.0/CaseFolding.txt` (Unicode 17.0.0).\n");
  out.push_str("//!\n");
  out.push_str("//! The generator includes only status `C` + `S` mappings (simple case folding) and\n");
  out.push_str("//! stores only non-identity mappings in a sorted table for binary search.\n");
  out.push_str("\n");

  out.push_str("#[inline]\n");
  out.push_str("pub(crate) fn scf(cp: u32) -> u32 {\n");
  out.push_str("  // Surrogates are not Unicode scalar values; per ECMA-262 `scf`, they fold to themselves.\n");
  out.push_str("  if (0xD800..=0xDFFF).contains(&cp) {\n");
  out.push_str("    return cp;\n");
  out.push_str("  }\n");
  out.push_str("  match SCF_TABLE.binary_search_by_key(&cp, |(from, _)| *from) {\n");
  out.push_str("    Ok(idx) => SCF_TABLE[idx].1,\n");
  out.push_str("    Err(_) => cp,\n");
  out.push_str("  }\n");
  out.push_str("}\n\n");

  out.push_str("#[rustfmt::skip]\n");
  out.push_str("const SCF_TABLE: &[(u32, u32)] = &[\n");
  for (from, to) in &mappings {
    out.push_str(&format!("  (0x{from:04X}, 0x{to:04X}),\n"));
  }
  out.push_str("];\n");

  Ok(out)
}

fn parse_hex_code_point(raw: &str) -> Result<u32, String> {
  let cp = u32::from_str_radix(raw.trim(), 16)
    .map_err(|e| format!("invalid hex code point {raw:?}: {e}"))?;
  if cp > 0x10FFFF {
    return Err(format!("code point out of range: {raw:?}"));
  }
  Ok(cp)
}
